import React, { useState, useEffect, useCallback } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { useAuth } from './context/AuthContext';
import { ThemeProvider } from './context/ThemeContext';
import { CartProvider } from './context/CartContext';
import Navbar from './components/Navbar/Navbar';
import Sidebar from './components/Sidebar/Sidebar';
import ChatWidget from './components/Chat/ChatWidget';
import HomePage from './pages/HomePage';
import ProductsPage from './pages/ProductsPage';
import ProductDetailPage from './pages/ProductDetailPage';
import CartPage from './pages/CartPage';
import CheckoutPage from './pages/CheckoutPage';
import OrdersPage from './pages/OrdersPage';
import OrderDetailPage from './pages/OrderDetailPage';
import TrackingPage from './pages/TrackingPage';
import AccountPage from './pages/AccountPage';
import SettingsPage from './pages/SettingsPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import Notificationspage from './pages/Notificationspage';
import Offerspage from './pages/Offerspage';
import { WishlistProvider } from './context/Wishlistcontext';
import PriceDropProductPage from './pages/PriceDropProductPage';
import WhishList from './pages/WhishList';
import WalletPage from './pages/WalletPage';
import { userAPI } from './api/api';
import toast from 'react-hot-toast';
import i18n from './i18n/i18n';

// Utility: Convert URL-safe base64 to ArrayBuffer
const urlBase64ToUint8Array = (base64String) => {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
};

// Protected Route Component
function ProtectedRoute({ children }) {
  const { isAuthenticated, loading } = useAuth();
  if (loading) return <div className="page-loader"><div className="spinner" /></div>;
  return isAuthenticated ? children : <Navigate to="/login" replace />;
}

// Push Notification Hook
function usePushNotifications() {
  const { user, isAuthenticated } = useAuth();
  const [pushSupported, setPushSupported] = useState(false);
  const [subscription, setSubscription] = useState(null);
  const [permission, setPermission] = useState('default');

  useEffect(() => {
    const supported = 'serviceWorker' in navigator && 'PushManager' in window && 'Notification' in window;
    setPushSupported(supported);
    if (supported && Notification.permission !== 'default') {
      setPermission(Notification.permission);
    }
  }, []);

  useEffect(() => {
    if (isAuthenticated && user?.id && pushSupported) {
      loadSubscription();
    }
  }, [isAuthenticated, user?.id, pushSupported]);

  const loadSubscription = async () => {
    try {
      const res = await userAPI.getPushSubscription();
      if (res.data?.data?.subscription) {
        setSubscription(res.data.data.subscription);
      }
    } catch (err) {
      console.warn('Could not load push subscription:', err);
    }
  };

  const registerServiceWorker = useCallback(async () => {
    try {
      const registration = await navigator.serviceWorker.register('/firebase-messaging-sw.js', {
        scope: '/',
        updateViaCache: 'none'
      });
      console.log('Service Worker registered:', registration.scope);
      return registration;
    } catch (err) {
      console.error('Service Worker registration failed:', err);
      throw err;
    }
  }, []);

  const subscribeUserToPush = useCallback(async () => {
    if (!pushSupported) {
      console.warn('Push notifications not supported');
      return null;
    }
    try {
      const perm = await Notification.requestPermission();
      setPermission(perm);
      if (perm !== 'granted') {
        if (perm === 'denied') console.warn('Notifications blocked by user');
        return null;
      }
      const registration = await registerServiceWorker();
      const VAPID_PUBLIC_KEY = process.env.REACT_APP_VAPID_PUBLIC_KEY;
      if (!VAPID_PUBLIC_KEY) {
        console.error('VAPID_PUBLIC_KEY not configured');
        return null;
      }
      const pushSubscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY)
      });
      const subscriptionData = JSON.parse(JSON.stringify(pushSubscription));
      await userAPI.savePushSubscription({
        endpoint: subscriptionData.endpoint,
        keys: subscriptionData.keys,
        userAgent: navigator.userAgent
      });
      setSubscription(subscriptionData);
      return subscriptionData;
    } catch (err) {
      console.error('Push subscription failed:', err);
      return null;
    }
  }, [pushSupported, registerServiceWorker]);

  const unsubscribeUser = useCallback(async () => {
    if (!subscription) return;
    try {
      const registration = await navigator.serviceWorker.ready;
      const pushSubscription = await registration.pushManager.getSubscription();
      if (pushSubscription) await pushSubscription.unsubscribe();
      await userAPI.deletePushSubscription();
      setSubscription(null);
    } catch (err) {
      console.error('Unsubscribe failed:', err);
    }
  }, [subscription]);

  useEffect(() => {
    if (!pushSupported || !isAuthenticated) return;
    const handleMessage = (event) => {
      try {
        const data = event.data?.json();
        if (data?.title || data?.body) {
          toast.custom((t) => (
            <div className={`push-toast ${t.visible ? 'enter' : 'exit'}`}>
              <strong>{data.title}</strong>
              {data.body && <p>{data.body}</p>}
              {data.url && <a href={data.url} className="toast-action">{data.actionText || 'View'}</a>}
            </div>
          ), { duration: 5000 });
        }
      } catch (err) { console.error('Error handling push message:', err); }
    };
    navigator.serviceWorker?.addEventListener('message', handleMessage);
    return () => navigator.serviceWorker?.removeEventListener('message', handleMessage);
  }, [pushSupported, isAuthenticated]);

  return {
    pushSupported,
    permission,
    subscription,
    subscribeUserToPush,
    unsubscribeUser,
    refreshPermission: () => setPermission(Notification.permission)
  };
}

function AppContent() {
  const { isAuthenticated } = useAuth();
  const { t, i18n } = useTranslation();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // 👇 FIX: Call hook ONCE at top level, store result in variable
  const push = usePushNotifications();
  const { pushSupported, permission, subscribeUserToPush } = push;

  // Update document title & lang attribute on language change
  useEffect(() => {
    document.title = t('home.title') || 'QualityProducts';
    document.documentElement.lang = i18n.language;
  }, [i18n.language, t]);

  // Sync push permission on tab focus
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && pushSupported) {
        push.refreshPermission();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [pushSupported, push]);

  // 👇 SAFETY: Wait for i18n to be ready before rendering to prevent blank screen
  const [i18nReady, setI18nReady] = useState(i18n.isInitialized);
  useEffect(() => {
    if (!i18n.isInitialized) {
      i18n.on('initialized', () => setI18nReady(true));
    } else {
      setI18nReady(true);
    }
    return () => i18n.off('initialized', () => setI18nReady(true));
  }, []);

  if (!i18nReady) {
    return (
      <div className="page-loader" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh' }}>
        <div className="spinner" style={{ width: '40px', height: '40px', border: '3px solid rgba(99,102,241,0.3)', borderTop: '3px solid #6366f1', borderRadius: '50%', animation: 'spin 1s linear infinite' }} />
        <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  return (
    // 🔑 CRITICAL FIX: key={i18n.language} forces re-render on language change
    <div className="app-layout" key={i18n.language}>
      {isAuthenticated && (
        <Sidebar 
          isOpen={sidebarOpen} 
          onClose={() => setSidebarOpen(false)}
          pushPermission={permission}
          onEnablePush={subscribeUserToPush}
        />
      )}

      <div className="main-content" style={!isAuthenticated ? { marginLeft: 0 } : undefined}>
        <Navbar 
          onMenuToggle={() => setSidebarOpen(!sidebarOpen)}
          // 👇 FIX: Use the stored 'push' variable, don't call hook in props
          pushStatus={{ 
            supported: pushSupported, 
            permission, 
            subscribed: !!push.subscription 
          }}
        />

        <main className="page-content">
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/products" element={<ProductsPage />} />
            <Route path="/products/:id" element={<ProductDetailPage />} />
            <Route path="/price-drop/:id" element={<ProtectedRoute><PriceDropProductPage /></ProtectedRoute>} />
            <Route path="/login" element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />
            <Route path="/cart" element={<ProtectedRoute><CartPage /></ProtectedRoute>} />
            <Route path="/checkout" element={<ProtectedRoute><CheckoutPage /></ProtectedRoute>} />
            <Route path="/orders" element={<ProtectedRoute><OrdersPage /></ProtectedRoute>} />
            <Route path="/orders/:id" element={<ProtectedRoute><OrderDetailPage /></ProtectedRoute>} />
            <Route path="/tracking" element={<TrackingPage />} />
            <Route path="/account" element={<ProtectedRoute><AccountPage /></ProtectedRoute>} />
            <Route path="/wallet" element={<ProtectedRoute><WalletPage /></ProtectedRoute>} />
            <Route path="/settings" element={
              <ProtectedRoute>
                <SettingsPage pushProps={{ supported: pushSupported, permission, onEnable: subscribeUserToPush }} />
              </ProtectedRoute>
            } />
            <Route path="/wishlist" element={<WhishList />} />
            <Route path="/notifications" element={<ProtectedRoute><Notificationspage /></ProtectedRoute>} />
            <Route path="/offers" element={<Offerspage />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
        <ChatWidget />
      </div>

      {/* Push permission prompt */}
      {isAuthenticated && pushSupported && permission === 'default' && (
        <div className="push-permission-banner" style={{
          position: 'fixed', bottom: 20, right: 20, background: 'var(--bg-card, #1a1d2d)',
          border: '1px solid var(--border-color, #2a2f45)', borderRadius: 12, padding: '12px 16px',
          boxShadow: '0 4px 20px rgba(0,0,0,0.15)', maxWidth: 320, zIndex: 1000,
          display: 'flex', alignItems: 'center', gap: 12
        }}>
          <span style={{ fontSize: '1.2rem' }}>🔔</span>
          <div style={{ flex: 1, fontSize: '0.9rem' }}>
            <strong>{t('notifications.getInstantUpdates') || 'Get instant updates'}</strong>
            <div style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>
              {t('notifications.enablePushDescription') || 'Enable push for orders, prices & security alerts'}
            </div>
          </div>
          <button onClick={subscribeUserToPush} className="btn btn-sm btn-primary" style={{ padding: '6px 14px', fontSize: '0.85rem' }}>
            {t('common.enable') || 'Enable'}
          </button>
        </div>
      )}
    </div>
  );
}

export default function App() {
  return (
    <ThemeProvider>
      <CartProvider>
        <WishlistProvider>
          <AppContent />
        </WishlistProvider>
      </CartProvider>
    </ThemeProvider>
  );
}
